<?php
session_start();
if (!isset($_SESSION['status']) || $_SESSION['status'] != "login") {
    header("location:login.php"); exit();
}

include 'koneksi.php';
require_once __DIR__ . '/vendor/autoload.php';

$id    = intval($_GET['id'] ?? 0);
$modul = $_GET['modul'] ?? 'test_running'; // test_running | final_inspection | packing

if ($id <= 0) { die("ID tidak valid."); }

// ============================================================
// Ambil data sesuai modul
// ============================================================
if ($modul === 'test_running') {

    $row = mysqli_fetch_assoc(mysqli_query($koneksi, "SELECT * FROM result_test_run WHERE id = $id"));
    if (!$row) die("Data tidak ditemukan.");

    // Cek sudah approved Foreman
    $apv = mysqli_fetch_assoc(mysqli_query($koneksi,
        "SELECT * FROM approvals WHERE test_run_id=$id AND stage='Test_Running' AND role='Foreman' AND status='approved'"
    ));
    if (!$apv) die("Data belum disetujui. PDF hanya tersedia untuk data yang sudah Approved.");

    // Ambil checklist
    $checklists = [];
    $q_chk = mysqli_query($koneksi, "SELECT * FROM checklist WHERE id_test_run = $id");
    if ($q_chk) while ($c = mysqli_fetch_assoc($q_chk)) $checklists[] = $c;

} elseif ($modul === 'final_inspection') {

    $row = mysqli_fetch_assoc(mysqli_query($koneksi, "SELECT * FROM final_inspection_data WHERE id = $id"));
    if (!$row) die("Data tidak ditemukan.");

    $apv = mysqli_fetch_assoc(mysqli_query($koneksi,
        "SELECT * FROM approvals WHERE test_run_id=$id AND stage='Final_Inspection' AND role='Supervisor' AND status='approved'"
    ));
    if (!$apv) die("Data belum disetujui penuh. PDF hanya tersedia setelah Supervisor approve.");

    // Ambil checklist FI
    $checklists = [];
    $q_chk = mysqli_query($koneksi, "SELECT * FROM final_inspection_checklist WHERE fi_id = $id");
    if ($q_chk) while ($c = mysqli_fetch_assoc($q_chk)) $checklists[] = $c;
}

// Ambil semua approval record untuk modul ini
$stage_map = ['test_running'=>'Test_Running','final_inspection'=>'Final_Inspection','packing'=>'Packing'];
$stage = $stage_map[$modul] ?? 'Test_Running';
$apv_all = [];
$q_apv = mysqli_query($koneksi, "SELECT * FROM approvals WHERE test_run_id=$id AND stage='$stage' ORDER BY id ASC");
if ($q_apv) while ($a = mysqli_fetch_assoc($q_apv)) $apv_all[$a['role']] = $a;

// ============================================================
// Foto engine
// ============================================================
$foto_base64 = '';
$foto_path   = $row['foto_engine'] ?? '';
if ($foto_path && file_exists($foto_path)) {
    $img_data    = file_get_contents($foto_path);
    $img_type    = mime_content_type($foto_path);
    $foto_base64 = 'data:'.$img_type.';base64,'.base64_encode($img_data);
}

// Logo Yanmar - embedded as base64
$logo_base64 = 'data:image/png;base64,';

// ============================================================
// Helper functions
// ============================================================
function e($str) { return htmlspecialchars($str ?? '-', ENT_QUOTES); }
function val($row, $key) { return isset($row[$key]) && $row[$key] !== '' ? e($row[$key]) : '-'; }

// ============================================================
// Build HTML untuk PDF
// ============================================================
$engine_model = val($row, 'engine_model');
$engine_no    = val($row, 'engine_no');
$operator     = val($row, 'operator_name');
$test_date    = isset($row['test_date'])    && $row['test_date']    ? date('d/m/Y', strtotime($row['test_date']))    : '-';
$inspect_date = isset($row['inspect_date']) && $row['inspect_date'] ? date('d/m/Y', strtotime($row['inspect_date'])) : '-';
$noted        = $row['noted'] ?? '';

// Approval info
$apv_foreman  = $apv_all['Foreman']    ?? null;
$apv_super    = $apv_all['Supervisor'] ?? null;
$apv_am       = $apv_all['Asst_Manager'] ?? null;

ob_start(); ?>
