<div class="section-title">APPROVAL & SIGNATURE</div>
<table class="apv-table">
    <?php
    $levels = $modul==='test_running'
        ? [['key'=>'Foreman','label'=>'Foreman']]
        : ($modul==='final_inspection'
            ? [['key'=>'Foreman','label'=>'Foreman'],['key'=>'Supervisor','label'=>'Supervisor']]
            : [['key'=>'Foreman','label'=>'Foreman'],['key'=>'Supervisor','label'=>'Supervisor'],['key'=>'Asst_Manager','label'=>'Asst. Manager']]);
    ?>
    <tr>
    <?php foreach($levels as $lvl):
        $a = $apv_all[$lvl['key']] ?? null;
        $status = $a['status'] ?? 'pending';
        $by     = $a['approved_by'] ?? '';
        $at     = $a ? date('d/m/Y H:i', strtotime($a['created_at'])) : '';
    ?>
        <td>
            <div class="apv-role"><?php echo $lvl['label']; ?></div>
            <?php if($status==='approved'): ?>
                <div class="apv-stamp-approved">✓ APPROVED</div>
            <?php elseif($status==='rejected'): ?>
                <div class="apv-stamp-rejected">✗ REJECTED</div>
            <?php else: ?>
                <div class="apv-stamp-pending">⏳ PENDING</div>
            <?php endif; ?>
            <div class="apv-name"><?php echo e($by) ?: '&nbsp;'; ?></div>
            <div class="apv-date"><?php echo $at ?: ''; ?></div>
        </td>
    <?php endforeach; ?>
    <?php // Isi kolom kosong kalau level < 3
    for($i=count($levels);$i<3;$i++) echo '<td></td>'; ?>
    </tr>
</table>

<div class="pdf-footer">
    Dokumen ini digenerate otomatis oleh sistem QC &mdash; <?php echo date('d/m/Y H:i:s'); ?>
</div>

</body>
</html>
<?php
$html = ob_get_clean();

// ============================================================
// Generate PDF dengan mPDF
// ============================================================
$mpdf = new \Mpdf\Mpdf([
    'mode'          => 'utf-8',
    'format'        => 'A4-L',
    'margin_top'    => 10,
    'margin_bottom' => 10,
    'margin_left'   => 10,
    'margin_right'  => 10,
]);
$mpdf->img_dpi = 96;
$mpdf->defaultCssFile = '';

$mpdf->SetTitle('QC Report - ' . $engine_no);

// Tambah pcre limit & tulis HTML dalam chunk kecil
@ini_set('pcre.backtrack_limit', '5000000');

// Pisah CSS dan body supaya tidak overload
preg_match('/<style>(.*?)<\/style>/s', $html, $style_match);
$css  = isset($style_match[1]) ? $style_match[1] : '';
$body = preg_replace('/<style>.*?<\/style>/s', '', $html);

$mpdf->WriteHTML($css, \Mpdf\HTMLParserMode::HEADER_CSS);
$mpdf->WriteHTML($body, \Mpdf\HTMLParserMode::HTML_BODY);

$filename = 'QC_' . strtoupper($modul) . '_' . $engine_no . '_' . date('Ymd') . '.pdf';
$mpdf->Output($filename, 'D');